     1→# ===========================================
     2→# NGINX MAIN CONFIGURATION
     3→# ===========================================
     4→# Security-hardened configuration for Common Cloud
     5→# Rate limiting, SSL hardening, and security headers included
     6→#
     7→# DEPLOYMENT: Copy to ~/commoncloud/nginx/nginx.conf on server
     8→# ===========================================
     9→
    10→events {
    11→    worker_connections 1024;
    12→}
    13→
    14→http {
    15→    # Logging
    16→    access_log /var/log/nginx/access.log;
    17→    error_log /var/log/nginx/error.log;
    18→
    19→    # Gzip compression
    20→    gzip on;
    21→    gzip_types text/plain text/css application/json application/javascript;
    22→
    23→    # ===========================================
    24→    # RATE LIMITING - Brute Force Protection
    25→    # ===========================================
    26→    # Zone: 10MB shared memory (~160,000 IP addresses)
    27→    # Rate: 10 requests/second per IP (burst allows short spikes)
    28→    limit_req_zone $binary_remote_addr zone=general:10m rate=10r/s;
    29→    limit_req_zone $binary_remote_addr zone=login:10m rate=5r/m;
    30→    limit_req_zone $binary_remote_addr zone=api:10m rate=30r/s;
    31→
    32→    # Return 429 Too Many Requests (not 503)
    33→    limit_req_status 429;
    34→
    35→    # Log rate limit violations
    36→    limit_req_log_level warn;
    37→
    38→    # ===========================================
    39→    # SECURITY HEADERS
    40→    # ===========================================
    41→    # Prevent clickjacking
    42→    add_header X-Frame-Options "SAMEORIGIN" always;
    43→    # Prevent MIME type sniffing
    44→    add_header X-Content-Type-Options "nosniff" always;
    45→    # Enable XSS filter
    46→    add_header X-XSS-Protection "1; mode=block" always;
    47→    # Referrer policy
    48→    add_header Referrer-Policy "strict-origin-when-cross-origin" always;
    49→
    50→    # ===========================================
    51→    # SSL HARDENING
    52→    # ===========================================
    53→    ssl_protocols TLSv1.2 TLSv1.3;
    54→    ssl_ciphers ECDHE-ECDSA-AES128-GCM-SHA256:ECDHE-RSA-AES128-GCM-SHA256:ECDHE-ECDSA-AES256-GCM-SHA384:ECDHE-RSA-AES256-GCM-SHA384;
    55→    ssl_prefer_server_ciphers off;
    56→    ssl_session_cache shared:SSL:10m;
    57→    ssl_session_timeout 1d;
    58→    ssl_session_tickets off;
    59→
    60→    # HSTS (uncomment after confirming SSL works)
    61→    # add_header Strict-Transport-Security "max-age=63072000" always;
    62→
    63→    # Include site configs (conf.d/cloudflare-real-ip.conf restores client IP when CF proxy is ON)
    64→    include /etc/nginx/conf.d/*.conf;
    65→}
