     1→# gifteddreamers.org - Static React Site with SSL
     2→
     3→# Redirect HTTP to HTTPS
     4→server {
     5→    listen 80;
     6→    server_name gifteddreamers.org www.gifteddreamers.org;
     7→
     8→    # ACME challenge for SSL cert renewal
     9→    location /.well-known/acme-challenge/ {
    10→        root /var/www/certbot;
    11→        try_files $uri =404;
    12→    }
    13→
    14→    location / {
    15→        return 301 https://$host$request_uri;
    16→    }
    17→}
    18→
    19→# HTTPS server
    20→server {
    21→    listen 443 ssl;
    22→    http2 on;
    23→    server_name gifteddreamers.org www.gifteddreamers.org;
    24→
    25→    ssl_certificate /etc/nginx/certs/gifteddreamers.org/fullchain.pem;
    26→    ssl_certificate_key /etc/nginx/certs/gifteddreamers.org/privkey.pem;
    27→
    28→    # SSL settings
    29→    ssl_protocols TLSv1.2 TLSv1.3;
    30→    ssl_ciphers ECDHE-ECDSA-AES128-GCM-SHA256:ECDHE-RSA-AES128-GCM-SHA256:ECDHE-ECDSA-AES256-GCM-SHA384:ECDHE-RSA-AES256-GCM-SHA384;
    31→    ssl_prefer_server_ciphers off;
    32→
    33→    root /var/www/gifteddreamers.org;
    34→    index index.html;
    35→
    36→    # Force correct MIME types
    37→    include /etc/nginx/mime.types;
    38→    default_type application/octet-stream;
    39→
    40→    # React SPA - all routes go to index.html
    41→    location / {
    42→        try_files $uri $uri/ /index.html;
    43→        # Short cache for HTML (allows quick updates)
    44→        add_header Cache-Control "public, max-age=3600";
    45→    }
    46→
    47→    # Cache static assets with hashed filenames (immutable)
    48→    location /assets/ {
    49→        expires 1y;
    50→        add_header Cache-Control "public, max-age=31536000, immutable";
    51→    }
    52→
    53→    # Cache images with longer lifetime
    54→    location ~* \.(jpg|jpeg|png|gif|ico|svg|webp)$ {
    55→        expires 1y;
    56→        add_header Cache-Control "public, max-age=31536000";
    57→    }
    58→
    59→    # Cache fonts
    60→    location ~* \.(woff|woff2|ttf|otf|eot)$ {
    61→        expires 1y;
    62→        add_header Cache-Control "public, max-age=31536000, immutable";
    63→    }
    64→
    65→    # Cache CSS and JS
    66→    location ~* \.(css|js)$ {
    67→        expires 1y;
    68→        add_header Cache-Control "public, max-age=31536000, immutable";
    69→    }
    70→
    71→    # Security headers (must be in location blocks or they get overwritten)
    72→    add_header X-Frame-Options "SAMEORIGIN" always;
    73→    add_header X-Content-Type-Options "nosniff" always;
    74→    add_header X-XSS-Protection "1; mode=block" always;
    75→    add_header Strict-Transport-Security "max-age=31536000; includeSubDomains" always;
    76→    add_header Referrer-Policy "strict-origin-when-cross-origin" always;
    77→
    78→    # Gzip compression
    79→    gzip on;
    80→    gzip_vary on;
    81→    gzip_min_length 1000;
    82→    gzip_types text/plain text/css application/json application/javascript text/xml application/xml application/xml+rss text/javascript image/svg+xml;
    83→}
