     6→const generateNiceTag = () => {
     7→  const chars = 'ABCDEFGHJKLMNPQRSTUVWXYZ23456789';
     8→  let tag = 'NICE-';
     9→  for (let i = 0; i < 6; i++) {
    10→    tag += chars.charAt(Math.floor(Math.random() * chars.length));
    11→  }
    12→  return tag;
    13→};
    14→
    15→const getUserTag = () => {
    16→  let tag = localStorage.getItem('niceTag');
    17→  if (!tag) {
    18→    tag = generateNiceTag();
    19→    localStorage.getItem('niceTag', tag);
    20→  }
    21→  return tag;
    22→};
    23→
    24→const getCurrentCycle = () => {
    25→  const now = new Date();
    26→  const hours = now.getHours();
    27→  const cycleStart = Math.floor(hours / 2) * 2;
    28→  const cycleStartTime = new Date(now);
    29→  cycleStartTime.setHours(cycleStart, 0, 0, 0);
    30→  return cycleStartTime;
    31→};
    32→
    33→const getBucketHash = (lat, lng) => {
    34→  return `${Math.floor(lat * 1000)}_${Math.floor(lng * 1000)}`;
    35→};
    36→
    37→const getTimeAgo = (timestamp) => {
    38→  const mins = Math.floor((Date.now() - new Date(timestamp).getTime()) / 60000);
    39→  if (mins < 60) return `${mins}m ago`;
    40→  const hours = Math.floor(mins / 60);
    41→  if (hours < 24) return `${hours}h ago`;
    42→  return `${Math.floor(hours / 24)}d ago`;
    43→};
    44→
    45→const App = () => {
    46→  const [activeTab, setActiveTab] = useState('map');
    47→  const [requests, setRequests] = useState([]);
    48→  const [userTag] = useState(getUserTag());
    49→  const [selectedPin, setSelectedPin] = useState(null);
    50→  const [newRequestText, setNewRequestText] = useState('');
