    52→  const [showAddModal, setShowAddModal] = useState(false);
    53→  const [pinAddress, setPinAddress] = useState('');
    54→  const [newPinLocation, setNewPinLocation] = useState(null);
    55→  
    56→  const mapRef = useRef(null);
    57→  const googleMapRef = useRef(null);
    58→  const markersRef = useRef([]);
    59→  const newPinMarkerRef = useRef(null);
    60→  const geocoderRef = useRef(null);
    61→
    62→  useEffect(() => {
    63→    const stored = localStorage.getItem('niceRequests');
    64→    if (stored) {
    65→      const parsed = JSON.parse(stored);
    66→      const active = parsed.filter(r => 
    67→        (Date.now() - new Date(r.createdAt).getTime()) < 24 * 60 * 60 * 1000
    68→      );
    69→      setRequests(active);
    70→    }
    71→  }, []);
    72→
    73→  useEffect(() => {
    74→    if (requests.length > 0) {
    75→      localStorage.setItem('niceRequests', JSON.stringify(requests));
    76→    }
    77→  }, [requests]);
    78→
    79→  useEffect(() => {
    80→    const script = document.createElement('script');
