    91→  const initMap = () => {
    92→    if (!window.google || !mapRef.current) return;
    93→
    94→    navigator.geolocation.getCurrentPosition(
    95→      (position) => {
    96→        const userLocation = {
    97→          lat: position.coords.latitude,
    98→          lng: position.coords.longitude
    99→        };
   100→        createMap(userLocation);
   101→      },
   102→      () => {
