   104→        createMap(defaultLocation);
   105→      }
   106→    );
   107→  };
   108→
   109→  const createMap = (center) => {
   110→    if (!window.google) return;
   111→
   112→    geocoderRef.current = new window.google.maps.Geocoder();
   113→    
   114→    googleMapRef.current = new window.google.maps.Map(mapRef.current, {
   115→      center: center,
   116→      zoom: 14,
   117→      mapTypeControl: false,
   118→      streetViewControl: false,
   119→      fullscreenControl: false
   120→    });
   121→
   122→    new window.google.maps.Marker({
   123→      position: center,
   124→      map: googleMapRef.current,
   125→      icon: {
   126→        path: window.google.maps.SymbolPath.CIRCLE,
   127→        scale: 8,
   128→        fillColor: '#667eea',
   129→        fillOpacity: 1,
   130→        strokeColor: 'white',
   131→        strokeWeight: 2
   132→      },
   133→      title: 'Your Location'
