   135→
   136→    renderMarkers();
   137→  };
   138→
   139→  const renderMarkers = () => {
   140→    if (!googleMapRef.current || !window.google) return;
   141→
   142→    markersRef.current.forEach(m => m.setMap(null));
   143→    markersRef.current = [];
   144→
   145→    requests.forEach(req => {
   146→      const color = req.completedCount > 0 ? '#10b981' : 
   147→                   req.frwWinner ? '#eab308' : '#667eea';
   148→
   149→      const marker = new window.google.maps.Marker({
   150→        position: { lat: req.lat, lng: req.lng },
   151→        map: googleMapRef.current,
   152→        icon: {
   153→          path: 'M12 0C7.31 0 3.5 3.81 3.5 8.5C3.5 14.88 12 24 12 24S20.5 14.88 20.5 8.5C20.5 3.81 16.69 0 12 0Z',
   154→          fillColor: color,
