   171→
   172→  const checkFRWAvailable = (lat, lng) => {
   173→    const bucket = getBucketHash(lat, lng);
   174→    const cycle = getCurrentCycle();
   175→    const cycleKey = `${bucket}_${cycle.getTime()}`;
   176→    
   177→    return !requests.some(r => 
   178→      r.bucketHash === bucket && 
   179→      r.cycleKey === cycleKey && 
   180→      r.frwWinner
   181→    );
   182→  };
   183→
   184→  const handleAddClick = () => {
   185→    if (!googleMapRef.current || !window.google) return;
   186→
   187→    setShowAddModal(true);
   188→    setNewRequestText('');
