   196→    
   197→    newPinMarkerRef.current = new window.google.maps.Marker({
   198→      position: position,
   199→      map: googleMapRef.current,
   200→      draggable: true,
   201→      icon: {
   202→        path: 'M12 0C7.31 0 3.5 3.81 3.5 8.5C3.5 14.88 12 24 12 24S20.5 14.88 20.5 8.5C20.5 3.81 16.69 0 12 0Z',
