   221→  };
   222→
   223→  const updateAddress = (position) => {
   224→    if (!geocoderRef.current) return;
   225→
   226→    geocoderRef.current.geocode({ location: position }, (results, status) => {
   227→      if (status === 'OK' && results[0]) {
