   236→    const bucket = getBucketHash(newPinLocation.lat, newPinLocation.lng);
   237→    const cycle = getCurrentCycle();
   238→    const cycleKey = `${bucket}_${cycle.getTime()}`;
   239→    const isFRW = checkFRWAvailable(newPinLocation.lat, newPinLocation.lng);
   240→
   241→    const newRequest = {
   242→      id: Date.now().toString(),
   243→      text: newRequestText.trim(),
   244→      lat: newPinLocation.lat,
   245→      lng: newPinLocation.lng,
   246→      bucketHash: bucket,
   247→      cycleKey: cycleKey,
   248→      createdAt: new Date().toISOString(),
   249→      requesterTag: userTag,
   250→      frwWinner: isFRW,
   251→      completedCount: 0,
   252→      completedBy: [],
   253→      status: 'active'
   254→    };
   255→
   256→    setRequests([...requests, newRequest]);
