# nginx configuration for justnice.us
# Static site — no SPA routing needed

server {
    listen 80;
    server_name justnice.us www.justnice.us;

    # Redirect HTTP to HTTPS
    return 301 https://$server_name$request_uri;
}

server {
    listen 443 ssl http2;
    server_name justnice.us www.justnice.us;

    # SSL certificates
    ssl_certificate /etc/letsencrypt/live/justnice.us/fullchain.pem;
    ssl_certificate_key /etc/letsencrypt/live/justnice.us/privkey.pem;

    # SSL settings
    ssl_protocols TLSv1.2 TLSv1.3;
    ssl_prefer_server_ciphers on;
    ssl_ciphers ECDHE-ECDSA-AES128-GCM-SHA256:ECDHE-RSA-AES128-GCM-SHA256;

    # Document root
    root /home/admin/commoncloud/sites/justnice.us;
    index index.html;

    # Gzip compression
    gzip on;
    gzip_vary on;
    gzip_min_length 1024;
    gzip_types text/plain text/css text/xml text/javascript application/javascript application/json application/xml;

    # Security headers
    add_header X-Frame-Options "SAMEORIGIN" always;
    add_header X-Content-Type-Options "nosniff" always;
    add_header X-XSS-Protection "1; mode=block" always;
    add_header Referrer-Policy "strict-origin-when-cross-origin" always;

    # Cache static assets
    location ~* \.(js|css|png|jpg|jpeg|gif|ico|svg|woff|woff2)$ {
        expires 1y;
        add_header Cache-Control "public, immutable";
    }

    # Static site routing — no SPA fallback
    location / {
        try_files $uri $uri/ =404;
    }

    # Deny access to markdown files
    location ~* \.md$ {
        deny all;
    }

    # Deny access to hidden files
    location ~ /\. {
        deny all;
    }

    # Deny access to JSON data files (optional, remove if resources.json needs direct access)
    # location ~* \.json$ {
    #     deny all;
    # }
}

